// Build a set of known item_ids from D1 response.
// Compare against incoming items and mark duplicates.
const d1Response = $input.first().json;
const results = d1Response?.result?.[0]?.results || [];
const knownIds = new Set(results.map(r => r.item_id).filter(Boolean));

// Retrieve the original items from the trigger input.
// The orchestrator passes items via the Execute Workflow node payload.
const allItems = $('Extract Item IDs').first().json.items || [];

const deduped = allItems.map(item => ({
  ...item,
  is_duplicate: knownIds.has(item.item_id)
}));

const newItems = deduped.filter(i => !i.is_duplicate);

return [{ json: { items: newItems, total_input: allItems.length, duplicates_dropped: allItems.length - newItems.length } }];
